INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("青空の下で謁見", 40, 2834, 5118061, 10118, 8, 0, 91002, 1, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 20063115, 2, 7, "ペコリーヌとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("未来の騎空団\nマスコット？", 40, 2835, 5118062, 10118, 8, 0, 91002, 1, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 20063115, 2, 7, "マホとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("お嬢さまからの\n緊急依頼", 40, 2837, 5118063, 10118, 8, 0, 91002, 1, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 20063115, 2, 7, "アキノとの出会い", "ランドソル市街地");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("黄金色の悩みごと", 40, 4108402, 5118064, 10118, 8, 0, 91002, 1, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 20063115, 2, 18, "ジュンとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("白熱！　格闘大会！", 40, 4107402, 5118065, 10118, 8, 0, 91002, 1, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 20063115, 2, 18, "カオリとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("祭り太鼓はオーエドの華", 40, 9000227, 5118066, 10118, 8, 1, 91002, 1, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 20063115, 2, 16, "ニノンとの出会い", "オーエド町");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("人気者は遅れて\nやってくる", 40, 2101181, 5118067, 10118, 8, 0, 91002, 1, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 20063115, 3, 19, "スズナとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("巫女・ミーツ・魔法少女", 40, 4109402, 5118068, 10118, 8, 0, 91002, 1, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 20063115, 3, 18, "ナナカとの出会い", "ランドソル市街地");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ネズ耳は二度なくなる", 40, 4305402, 5118069, 10118, 8, 0, 91002, 1, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 20063115, 3, 18, "キャル＆コッコロとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("この出会いにカンパイ！", 40, 4101402, 5118070, 10118, 8, 0, 91002, 1, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 20063115, 3, 18, "ユカリとの出会い", "ランドソル市街地");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("陰陽アンサンブル", 40, 4106402, 5118071, 10118, 8, 0, 91002, 1, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 20063115, 3, 18, "アオイとの出会い", "ランドソル市街地");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("運試し十番勝負！", 40, 2836, 5118072, 10118, 8, 1, 91002, 1, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 20063115, 3, 7, "シノブとの出会い", "フリーマーケット会場");
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("彼女たちの新たな日常", 0, 0, 5118600, 10118, 0, 0, 0, 0, 0, 20063115, 1, 0, "オープニング", 0);
